// Handles both Twilio StatusCallback and CallRail notification formats.
// Sets is_valid_missed = true only for actual missed-call events —
// guards against completed calls that Twilio also fires StatusCallback on.

const item = $input.first().json;
const raw  = item.body || item; // some n8n webhook configs wrap inside .body

const TWILIO_MISSED = new Set(['no-answer', 'busy', 'failed', 'canceled']);

let normalized;
if (raw.CallStatus !== undefined) {
  // Twilio StatusCallback shape
  const callerNum = raw.Caller || raw.From || '';
  normalized = {
    caller_number:   callerNum,
    caller_name:     raw.CallerName || 'Unknown Caller',
    firm_number:     raw.Called || raw.To || '',
    call_status:     raw.CallStatus,
    source:          'twilio',
    is_valid_missed: TWILIO_MISSED.has(raw.CallStatus) && callerNum !== '',
  };
} else {
  // CallRail notification shape
  const callerNum = raw.caller_number || raw.caller_phone_number || '';
  normalized = {
    caller_number:   callerNum,
    caller_name:     raw.caller_name || raw.customer_name || 'Unknown Caller',
    firm_number:     raw.business_phone_number || raw.tracking_number || '',
    call_status:     'missed',
    source:          'callrail',
    is_valid_missed: callerNum !== '',
  };
}

return [{ json: { ...normalized, timestamp: new Date().toISOString() } }];

// Reads firm timezone and business hours from n8n Variables (project → Variables tab).
// Set: FIRM_TIMEZONE, FIRM_BUSINESS_HOURS_START, FIRM_BUSINESS_HOURS_END, FIRM_WORK_DAYS
const TIMEZONE             = $vars.FIRM_TIMEZONE;                                                   // e.g. 'America/Chicago', 'America/Los_Angeles'
const BUSINESS_HOURS_START = parseInt($vars.FIRM_BUSINESS_HOURS_START, 10);                         // 9 AM (inclusive)
const BUSINESS_HOURS_END   = parseInt($vars.FIRM_BUSINESS_HOURS_END, 10);                           // 5 PM (exclusive)
const WORK_DAYS            = ($vars.FIRM_WORK_DAYS || '1,2,3,4,5').split(',').map(Number);          // 0=Sun, 1=Mon … 6=Sat

const now       = new Date();
const localTime = new Date(now.toLocaleString('en-US', { timeZone: TIMEZONE }));
const hour      = localTime.getHours();
const day       = localTime.getDay();

const isAfterHours = !WORK_DAYS.includes(day)
  || hour < BUSINESS_HOURS_START
  || hour >= BUSINESS_HOURS_END;

const item = $input.first().json;
return [{ json: { ...item, is_after_hours: isAfterHours } }];

// Reads firm details from n8n Variables (project → Variables tab).
// Set: FIRM_NAME, FIRM_BOOKING_URL, FIRM_EMAIL, FIRM_TWILIO_NUMBER
const FIRM_NAME           = $vars.FIRM_NAME;
const BOOKING_URL         = $vars.FIRM_BOOKING_URL;
const FIRM_EMAIL          = $vars.FIRM_EMAIL;
const FIRM_TWILIO_NUMBER  = $vars.FIRM_TWILIO_NUMBER; // Your Twilio sending number

const item      = $input.first().json;
const rawFirst  = (item.caller_name || '').split(' ')[0];
const firstName = rawFirst && rawFirst !== 'Unknown' ? rawFirst : '';
const greeting  = firstName ? `Hi ${firstName}` : 'Hi';

const smsText = item.is_after_hours
  ? `${greeting}, this is ${FIRM_NAME}. We're currently closed but we want to help. Book a free consult: ${BOOKING_URL} — Reply STOP to opt out.`
  : `${greeting}, this is ${FIRM_NAME}. We missed your call and want to help. Book a free consult: ${BOOKING_URL} — Reply STOP to opt out.`;

return [{ json: {
  ...item,
  sms_text:           smsText,
  firm_email:         FIRM_EMAIL,
  firm_twilio_number: FIRM_TWILIO_NUMBER,
  firm_name:          FIRM_NAME,
  booking_url:        BOOKING_URL,
} }];

